CREATE OR REPLACE FUNCTION intermodal_transfer.cleanup_expired_idempotency_keys()
RETURNS void LANGUAGE plpgsql VOLATILE 
AS $$
BEGIN
  DELETE FROM intermodal_transfer.idempotency_keys WHERE expires_at < NOW();
END;
$$;

